{"path": "/tmp/sv-ef188221efb64a248afc7969b525d8d8/Components/Pages/Catalog/CatalogFilters.razor", "file_text": "<div class="p-3">
    <h5>Filters</h5>

    <div class="mb-3">
        <label class="form-label fw-bold">Categories</label>
        @foreach (var category in Categories)
        {
            <div class="form-check" @key="category">
                <input class="form-check-input" type="checkbox" id="@($"cat-{category}")"
                       checked="@selectedCategories.Contains(category)"
                       @onchange="() => ToggleCategory(category)" />
                <label class="form-check-label" for="@($"cat-{category}")">@category</label>
            </div>
        }
    </div>

    <div class="mb-3">
        <label class="form-label fw-bold">Min Price</label>
        <input type="number" class="form-control" @bind="minPrice" min="0" step="0.01" />
    </div>

    <div class="mb-3">
        <label class="form-label fw-bold">Max Price</label>
        <input type="number" class="form-control" @bind="maxPrice" min="0" step="0.01" />
    </div>

    <div class="form-check mb-3">
        <input class="form-check-input" type="checkbox" id="inStockOnly" @bind="inStockOnly" />
        <label class="form-check-label" for="inStockOnly">In Stock Only</label>
    </div>

    <div class="d-grid gap-2">
        <button class="btn btn-primary" @onclick="ApplyFilters">Apply Filters</button>
        <button class="btn btn-outline-secondary" @onclick="ClearFilters">Clear Filters</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public IReadOnlyList<string> Categories { get; set; } = [];
    [Parameter] public EventCallback<ProductFilter> OnFilterApplied { get; set; }

    private HashSet<string> selectedCategories = [];
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;

    private void ToggleCategory(string category)
    {
        if (!selectedCategories.Remove(category))
        {
            selectedCategories.Add(category);
        }
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
            MinPrice: minPrice,
            MaxPrice: maxPrice,
            InStockOnly: inStockOnly
        );
        await OnFilterApplied.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        selectedCategories = [];
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        await OnFilterApplied.InvokeAsync(new ProductFilter(null, null, null, false));
    }
}
"}

{"path": "/tmp/sv-ef188221efb64a248afc7969b525d8d8/Components/Pages/Catalog/CatalogToolbar.razor", "file_text": "<div class="d-flex justify-content-between align-items-center mb-3">
    <div>
        <label class="me-2">Sort by:</label>
        <select class="form-select d-inline-block w-auto" value="@SortBy" @onchange="HandleSortChanged">
            <option value="price_asc">Price: Low to High</option>
            <option value="price_desc">Price: High to Low</option>
            <option value="name_asc">Name: A-Z</option>
            <option value="rating_desc">Rating: Highest</option>
        </select>
    </div>
    <span class="text-muted">
        @if (TotalCount > 0)
        {
            var start = (Page - 1) * PageSize + 1;
            var end = Math.Min(Page * PageSize, TotalCount);
            <text>Showing @start–@end of @TotalCount products</text>
        }
        else
        {
            <text>No products</text>
        }
    </span>
</div>

@code {
    [Parameter, EditorRequired] public string SortBy { get; set; } = "";
    [Parameter] public int TotalCount { get; set; }
    [Parameter] public int Page { get; set; }
    [Parameter] public int PageSize { get; set; }
    [Parameter] public EventCallback<string> OnSortChanged { get; set; }

    private async Task HandleSortChanged(ChangeEventArgs e)
    {
        await OnSortChanged.InvokeAsync(e.Value?.ToString() ?? "price_asc");
    }
}
"}

{"path": "/tmp/sv-ef188221efb64a248afc7969b525d8d8/Components/Pages/Catalog/CatalogPagination.razor", "file_text": "@if (TotalPages > 1)
{
    <nav class="mt-4">
        <ul class="pagination justify-content-center">
            <li class="page-item @(Page <= 1 ? "disabled" : "")">
                <button class="page-link" @onclick="() => GoToPage(Page - 1)" disabled="@(Page <= 1)">Previous</button>
            </li>
            @for (var i = 1; i <= TotalPages; i++)
            {
                var pageNumber = i;
                <li class="page-item @(pageNumber == Page ? "active" : "")" @key="pageNumber">
                    <button class="page-link" @onclick="() => GoToPage(pageNumber)">@pageNumber</button>
                </li>
            }
            <li class="page-item @(Page >= TotalPages ? "disabled" : "")">
                <button class="page-link" @onclick="() => GoToPage(Page + 1)" disabled="@(Page >= TotalPages)">Next</button>
            </li>
        </ul>
    </nav>
}

@code {
    [Parameter] public int Page { get; set; }
    [Parameter] public int TotalPages { get; set; }
    [Parameter] public EventCallback<int> OnPageChanged { get; set; }

    private async Task GoToPage(int page)
    {
        if (page >= 1 && page <= TotalPages && page != Page)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }
}
"}

