+<div class="p-3">
+    <h5>Filters</h5>
+
+    <div class="mb-3">
+        <label class="form-label fw-bold">Categories</label>
+        @foreach (var category in Categories)
+        {
+            <div class="form-check" @key="category">
+                <input class="form-check-input" type="checkbox" id="@($"cat-{category}")"
+                       checked="@selectedCategories.Contains(category)"
+                       @onchange="() => ToggleCategory(category)" />
+                <label class="form-check-label" for="@($"cat-{category}")">@category</label>
+            </div>
+        }
+    </div>
+
+    <div class="mb-3">
+        <label class="form-label fw-bold">Min Price</label>
+        <input type="number" class="form-control" @bind="minPrice" min="0" step="0.01" />
+    </div>
+
+    <div class="mb-3">
+        <label class="form-label fw-bold">Max Price</label>
+        <input type="number" class="form-control" @bind="maxPrice" min="0" step="0.01" />
+    </div>
+
+    <div class="form-check mb-3">
+        <input class="form-check-input" type="checkbox" id="inStockOnly" @bind="inStockOnly" />
+        <label class="form-check-label" for="inStockOnly">In Stock Only</label>
+    </div>
+
+    <div class="d-grid gap-2">
+        <button class="btn btn-primary" @onclick="ApplyFilters">Apply Filters</button>
+        <button class="btn btn-outline-secondary" @onclick="ClearFilters">Clear Filters</button>
+    </div>
+</div>
+
+@code {
+    [Parameter, EditorRequired] public IReadOnlyList<string> Categories { get; set; } = [];
+    [Parameter] public EventCallback<ProductFilter> OnFilterApplied { get; set; }
+
+    private HashSet<string> selectedCategories = [];
+    private decimal? minPrice;
+    private decimal? maxPrice;
+    private bool inStockOnly;
+
+    private void ToggleCategory(string category)
+    {
+        if (!selectedCategories.Remove(category))
+        {
+            selectedCategories.Add(category);
+        }
+    }
+
+    private async Task ApplyFilters()
+    {
+        var filter = new ProductFilter(
+            Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
+            MinPrice: minPrice,
+            MaxPrice: maxPrice,
+            InStockOnly: inStockOnly
+        );
+        await OnFilterApplied.InvokeAsync(filter);
+    }
+
+    private async Task ClearFilters()
+    {
+        selectedCategories = [];
+        minPrice = null;
+        maxPrice = null;
+        inStockOnly = false;
+        await OnFilterApplied.InvokeAsync(new ProductFilter(null, null, null, false));
+    }
+}
+

